### Step 2.5: Rewrite ImportService

File: `src/Haven.Finance.MasterDataImport.Web/Services/ImportService.cs`

New implementation using only HttpClient. No more IAmazonS3, ILambdaInvoker, or IOptions.

```csharp
namespace Haven.Finance.MasterDataImport.Web.Services;

/// <summary>
/// Orchestrates the import workflow via API endpoints and presigned S3 URLs.
/// </summary>
public sealed class ImportService(HttpClient httpClient)
{
    /// <summary>
    /// Uploads a spreadsheet to S3 via a presigned URL.
    /// </summary>
    public async Task<string> UploadAsync(Stream file, string fileName, CancellationToken ct = default)
    {
        var safeName = Path.GetFileName(fileName);
        if (!safeName.EndsWith(".xlsx", StringComparison.OrdinalIgnoreCase))
        {
            throw new ArgumentException("Only .xlsx files are supported.", nameof(fileName));
        }

        // Get presigned upload URL from API
        var urlResponse = await httpClient.PostAsJsonAsync(
            "/api/upload-url",
            new UploadUrlRequest { FileName = safeName },
            WebSerializerContext.Default.UploadUrlRequest,
            ct).ConfigureAwait(false);
        urlResponse.EnsureSuccessStatusCode();

        var uploadInfo = await urlResponse.Content.ReadFromJsonAsync(
            WebSerializerContext.Default.UploadUrlResponse, ct).ConfigureAwait(false)
            ?? throw new InvalidOperationException("Failed to read upload URL response");

        // Upload file directly to S3 via presigned URL
        using var fileContent = new StreamContent(file);
        fileContent.Headers.ContentType =
            new System.Net.Http.Headers.MediaTypeHeaderValue(
                "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet");

        using var s3Client = new HttpClient();
        using var putResponse = await s3Client.PutAsync(uploadInfo.UploadUrl, fileContent, ct)
            .ConfigureAwait(false);
        putResponse.EnsureSuccessStatusCode();

        return uploadInfo.S3Key;
    }

    /// <summary>
    /// Invokes the API in validate mode and returns the validation report.
    /// </summary>
    public async Task<ValidationReport> ValidateAsync(
        string s3Key, string companyId, CancellationToken ct = default)
    {
        await RunAsync(s3Key, "validate", companyId, ct).ConfigureAwait(false);
        return await GetResultAsync(s3Key, "validation", WebSerializerContext.Default.ValidationReport, ct)
            .ConfigureAwait(false);
    }

    /// <summary>
    /// Invokes the API in dry-run mode and returns the preview payloads.
    /// </summary>
    public async Task<IReadOnlyList<ErpxProjectPayload>> PreviewAsync(
        string s3Key, string companyId, CancellationToken ct = default)
    {
        await RunAsync(s3Key, "dry-run", companyId, ct).ConfigureAwait(false);
        return await GetResultAsync(
            s3Key, "preview", WebSerializerContext.Default.IReadOnlyListErpxProjectPayload, ct)
            .ConfigureAwait(false);
    }

    /// <summary>
    /// Invokes the API in execute mode and returns the import result.
    /// </summary>
    public async Task<ImportResult> ExecuteAsync(
        string s3Key, string companyId, CancellationToken ct = default)
    {
        await RunAsync(s3Key, "execute", companyId, ct).ConfigureAwait(false);
        return await GetResultAsync(s3Key, "result", WebSerializerContext.Default.ImportResult, ct)
            .ConfigureAwait(false);
    }

    private async Task RunAsync(string s3Key, string mode, string companyId, CancellationToken ct)
    {
        var payload = new RunRequest { S3Key = s3Key, Mode = mode, CompanyId = companyId };
        using var response = await httpClient.PostAsJsonAsync(
            "/api/run", payload, WebSerializerContext.Default.RunRequest, ct).ConfigureAwait(false);
        response.EnsureSuccessStatusCode();
    }

    private async Task<T> GetResultAsync<T>(
        string s3Key, string suffix,
        System.Text.Json.Serialization.Metadata.JsonTypeInfo<T> typeInfo,
        CancellationToken ct)
    {
        var urlResponse = await httpClient.PostAsJsonAsync(
            "/api/result-url",
            new ResultUrlRequest { S3Key = s3Key, Suffix = suffix },
            WebSerializerContext.Default.ResultUrlRequest,
            ct).ConfigureAwait(false);
        urlResponse.EnsureSuccessStatusCode();

        var resultInfo = await urlResponse.Content.ReadFromJsonAsync(
            WebSerializerContext.Default.ResultUrlResponse, ct).ConfigureAwait(false)
            ?? throw new InvalidOperationException("Failed to read result URL response");

        using var s3Client = new HttpClient();
        using var resultStream = await s3Client.GetStreamAsync(resultInfo.ResultUrl, ct)
            .ConfigureAwait(false);

        return await JsonSerializer.DeserializeAsync(resultStream, typeInfo, ct).ConfigureAwait(false)
            ?? throw new InvalidOperationException($"Failed to deserialize result for {s3Key}/{suffix}");
    }
}
```

